1	import { describeAccountSnapshot } from "openclaw/plugin-sdk/account-helpers";
2	import { formatNormalizedAllowFromEntries } from "openclaw/plugin-sdk/allow-from";
3	import {
4	  adaptScopedAccountAccessor,
5	  createScopedChannelConfigAdapter,
6	  createScopedDmSecurityResolver,
7	} from "openclaw/plugin-sdk/channel-config-helpers";
8	import {
9	  composeAccountWarningCollectors,
10	  composeWarningCollectors,
11	  createAllowlistProviderOpenWarningCollector,
12	} from "openclaw/plugin-sdk/channel-policy";
13	import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";
14	import {
15	  createChannelDirectoryAdapter,
16	  createResolvedDirectoryEntriesLister,
17	} from "openclaw/plugin-sdk/directory-runtime";
18	import { runStoppablePassiveMonitor } from "openclaw/plugin-sdk/extension-shared";
19	import {
20	  createComputedAccountStatusAdapter,
21	  createDefaultChannelRuntimeState,
22	} from "openclaw/plugin-sdk/status-helpers";
23	import {
24	  listIrcAccountIds,
25	  resolveDefaultIrcAccountId,
26	  resolveIrcAccount,
27	  type ResolvedIrcAccount,
28	} from "./accounts.js";
29	import { IrcChannelConfigSchema } from "./config-schema.js";
30	import { monitorIrcProvider } from "./monitor.js";
31	import {
32	  normalizeIrcMessagingTarget,
33	  looksLikeIrcTargetId,
34	  isChannelTarget,
35	  normalizeIrcAllowEntry,
36	} from "./normalize.js";
37	import { resolveIrcGroupMatch, resolveIrcRequireMention } from "./policy.js";
38	import { probeIrc } from "./probe.js";
39	import {
40	  buildBaseChannelStatusSummary,
41	  createAccountStatusSink,
42	  chunkTextForOutbound,
43	  DEFAULT_ACCOUNT_ID,
44	  getChatChannelMeta,
45	  PAIRING_APPROVED_MESSAGE,
46	  type ChannelPlugin,
47	} from "./runtime-api.js";
48	import { getIrcRuntime } from "./runtime.js";
49	import { sendMessageIrc } from "./send.js";
50	import { ircSetupAdapter } from "./setup-core.js";
51	import { ircSetupWizard } from "./setup-surface.js";
52	import type { CoreConfig, IrcProbe } from "./types.js";
53	
54	const meta = getChatChannelMeta("irc");
55	
56	function normalizePairingTarget(raw: string): string {
57	  const normalized = normalizeIrcAllowEntry(raw);
58	  if (!normalized) {
59	    return "";
60	  }
61	  return normalized.split(/[!@]/, 1)[0]?.trim() ?? "";
62	}
63	
64	const listIrcDirectoryPeersFromConfig = createResolvedDirectoryEntriesLister<ResolvedIrcAccount>({
65	  kind: "user",
66	  resolveAccount: adaptScopedAccountAccessor(resolveIrcAccount),
67	  resolveSources: (account) => [
68	    account.config.allowFrom ?? [],
69	    account.config.groupAllowFrom ?? [],
70	    ...Object.values(account.config.groups ?? {}).map((group) => group.allowFrom ?? []),
71	  ],
72	  normalizeId: (entry) => normalizePairingTarget(entry) || null,
73	});
74	
75	const listIrcDirectoryGroupsFromConfig = createResolvedDirectoryEntriesLister<ResolvedIrcAccount>({
76	  kind: "group",
77	  resolveAccount: adaptScopedAccountAccessor(resolveIrcAccount),
78	  resolveSources: (account) => [
79	    account.config.channels ?? [],
80	    Object.keys(account.config.groups ?? {}),
81	  ],
82	  normalizeId: (entry) => {
83	    const normalized = normalizeIrcMessagingTarget(entry);
84	    return normalized && isChannelTarget(normalized) ? normalized : null;
85	  },
86	});
87	
88	const ircConfigAdapter = createScopedChannelConfigAdapter<
89	  ResolvedIrcAccount,
90	  ResolvedIrcAccount,
91	  CoreConfig
92	>({
93	  sectionKey: "irc",
94	  listAccountIds: listIrcAccountIds,
95	  resolveAccount: adaptScopedAccountAccessor(resolveIrcAccount),
96	  defaultAccountId: resolveDefaultIrcAccountId,
97	  clearBaseFields: [
98	    "name",
99	    "host",
100	    "port",
101	    "tls",
102	    "nick",
103	    "username",
104	    "realname",
105	    "password",
106	    "passwordFile",
107	    "channels",
108	  ],
109	  resolveAllowFrom: (account: ResolvedIrcAccount) => account.config.allowFrom,
110	  formatAllowFrom: (allowFrom) =>
111	    formatNormalizedAllowFromEntries({
112	      allowFrom,
113	      normalizeEntry: normalizeIrcAllowEntry,
114	    }),
115	  resolveDefaultTo: (account: ResolvedIrcAccount) => account.config.defaultTo,
116	});
117	
118	const resolveIrcDmPolicy = createScopedDmSecurityResolver<ResolvedIrcAccount>({
119	  channelKey: "irc",
120	  resolvePolicy: (account) => account.config.dmPolicy,
121	  resolveAllowFrom: (account) => account.config.allowFrom,
122	  policyPathSuffix: "dmPolicy",
123	  normalizeEntry: (raw) => normalizeIrcAllowEntry(raw),
124	});
125	
126	const collectIrcGroupPolicyWarnings =
127	  createAllowlistProviderOpenWarningCollector<ResolvedIrcAccount>({
128	    providerConfigPresent: (cfg) => cfg.channels?.irc !== undefined,
129	    resolveGroupPolicy: (account) => account.config.groupPolicy,
130	    buildOpenWarning: {
131	      surface: "IRC channels",
132	      openBehavior: "allows all channels and senders (mention-gated)",
133	      remediation: 'Prefer channels.irc.groupPolicy="allowlist" with channels.irc.groups',
134	    },
135	  });
136	
137	const collectIrcSecurityWarnings = composeAccountWarningCollectors<
138	  ResolvedIrcAccount,
139	  {
140	    account: ResolvedIrcAccount;
141	    cfg: CoreConfig;
142	  }
143	>(
144	  collectIrcGroupPolicyWarnings,
145	  (account) =>
146	    !account.config.tls &&
147	    "- IRC TLS is disabled (channels.irc.tls=false); traffic and credentials are plaintext.",
148	  (account) =>
149	    account.config.nickserv?.register &&
150	    '- IRC NickServ registration is enabled (channels.irc.nickserv.register=true); this sends "REGISTER" on every connect. Disable after first successful registration.',
151	  (account) =>
152	    account.config.nickserv?.register &&
153	    !account.config.nickserv.password?.trim() &&
154	    "- IRC NickServ registration is enabled but no NickServ password is resolved; set channels.irc.nickserv.password, channels.irc.nickserv.passwordFile, or IRC_NICKSERV_PASSWORD.",
155	);
156	
157	export const ircPlugin: ChannelPlugin<ResolvedIrcAccount, IrcProbe> = createChatChannelPlugin({
158	  base: {
159	    id: "irc",
160	    meta: {
161	      ...meta,
162	      quickstartAllowFrom: true,
163	    },
164	    setup: ircSetupAdapter,
165	    setupWizard: ircSetupWizard,
166	    capabilities: {
167	      chatTypes: ["direct", "group"],
168	      media: true,
169	      blockStreaming: true,
170	    },
171	    reload: { configPrefixes: ["channels.irc"] },
172	    configSchema: IrcChannelConfigSchema,
173	    config: {
174	      ...ircConfigAdapter,
175	      isConfigured: (account) => account.configured,
176	      describeAccount: (account) =>
177	        describeAccountSnapshot({
178	          account,
179	          configured: account.configured,
180	          extra: {
181	            host: account.host,
182	            port: account.port,
183	            tls: account.tls,
184	            nick: account.nick,
185	            passwordSource: account.passwordSource,
186	          },
187	        }),
188	    },
189	    groups: {
190	      resolveRequireMention: ({ cfg, accountId, groupId }) => {
191	        const account = resolveIrcAccount({ cfg: cfg as CoreConfig, accountId });
192	        if (!groupId) {
193	          return true;
194	        }
195	        const match = resolveIrcGroupMatch({ groups: account.config.groups, target: groupId });
196	        return resolveIrcRequireMention({
197	          groupConfig: match.groupConfig,
198	          wildcardConfig: match.wildcardConfig,
199	        });
200	      },
201	      resolveToolPolicy: ({ cfg, accountId, groupId }) => {
202	        const account = resolveIrcAccount({ cfg: cfg as CoreConfig, accountId });
203	        if (!groupId) {
204	          return undefined;
205	        }
206	        const match = resolveIrcGroupMatch({ groups: account.config.groups, target: groupId });
207	        return match.groupConfig?.tools ?? match.wildcardConfig?.tools;
208	      },
209	    },
210	    messaging: {
211	      normalizeTarget: normalizeIrcMessagingTarget,
212	      targetResolver: {
213	        looksLikeId: looksLikeIrcTargetId,
214	        hint: "<#channel|nick>",
215	      },
216	    },
217	    resolver: {
218	      resolveTargets: async ({ inputs, kind }) => {
219	        return inputs.map((input) => {
220	          const normalized = normalizeIrcMessagingTarget(input);
221	          if (!normalized) {
222	            return {
223	              input,
224	              resolved: false,
225	              note: "invalid IRC target",
226	            };
227	          }
228	          if (kind === "group") {
229	            const groupId = isChannelTarget(normalized) ? normalized : `#${normalized}`;
230	            return {
231	              input,
232	              resolved: true,
233	              id: groupId,
234	              name: groupId,
235	            };
236	          }
237	          if (isChannelTarget(normalized)) {
238	            return {
239	              input,
240	              resolved: false,
241	              note: "expected user target",
242	            };
243	          }
244	          return {
245	            input,
246	            resolved: true,
247	            id: normalized,
248	            name: normalized,
249	          };
250	        });
251	      },
252	    },
253	    directory: createChannelDirectoryAdapter({
254	      listPeers: async (params) => listIrcDirectoryPeersFromConfig(params),
255	      listGroups: async (params) => {
256	        const entries = await listIrcDirectoryGroupsFromConfig(params);
257	        return entries.map((entry) => ({ ...entry, name: entry.id }));
258	      },
259	    }),
260	    status: createComputedAccountStatusAdapter<ResolvedIrcAccount, IrcProbe>({
261	      defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
262	      buildChannelSummary: ({ account, snapshot }) => ({
263	        ...buildBaseChannelStatusSummary(snapshot),
264	        host: account.host,
265	        port: snapshot.port,
266	        tls: account.tls,
267	        nick: account.nick,
268	        probe: snapshot.probe,
269	        lastProbeAt: snapshot.lastProbeAt ?? null,
270	      }),
271	      probeAccount: async ({ cfg, account, timeoutMs }) =>
272	        probeIrc(cfg as CoreConfig, { accountId: account.accountId, timeoutMs }),
273	      resolveAccountSnapshot: ({ account }) => ({
274	        accountId: account.accountId,
275	        name: account.name,
276	        enabled: account.enabled,
277	        configured: account.configured,
278	        extra: {
279	          host: account.host,
280	          port: account.port,
281	          tls: account.tls,
282	          nick: account.nick,
283	          passwordSource: account.passwordSource,
284	        },
285	      }),
286	    }),
287	    gateway: {
288	      startAccount: async (ctx) => {
289	        const account = ctx.account;
290	        const statusSink = createAccountStatusSink({
291	          accountId: ctx.accountId,
292	          setStatus: ctx.setStatus,
293	        });
294	        if (!account.configured) {
295	          throw new Error(
296	            `IRC is not configured for account "${account.accountId}" (need host and nick in channels.irc).`,
297	          );
298	        }
299	        ctx.log?.info(
300	          `[${account.accountId}] starting IRC provider (${account.host}:${account.port}${account.tls ? " tls" : ""})`,
301	        );
302	        await runStoppablePassiveMonitor({
303	          abortSignal: ctx.abortSignal,
304	          start: async () =>
305	            await monitorIrcProvider({
306	              accountId: account.accountId,
307	              config: ctx.cfg as CoreConfig,
308	              runtime: ctx.runtime,
309	              abortSignal: ctx.abortSignal,
310	              statusSink,
311	            }),
312	        });
313	      },
314	    },
315	  },
316	  pairing: {
317	    text: {
318	      idLabel: "ircUser",
319	      message: PAIRING_APPROVED_MESSAGE,
320	      normalizeAllowEntry: (entry) => normalizeIrcAllowEntry(entry),
321	      notify: async ({ id, message }) => {
322	        const target = normalizePairingTarget(id);
323	        if (!target) {
324	          throw new Error(`invalid IRC pairing id: ${id}`);
325	        }
326	        await sendMessageIrc(target, message);
327	      },
328	    },
329	  },
330	  security: {
331	    resolveDmPolicy: resolveIrcDmPolicy,
332	    collectWarnings: collectIrcSecurityWarnings,
333	  },
334	  outbound: {
335	    base: {
336	      deliveryMode: "direct",
337	      chunker: chunkTextForOutbound,
338	      chunkerMode: "markdown",
339	      textChunkLimit: 350,
340	    },
341	    attachedResults: {
342	      channel: "irc",
343	      sendText: async ({ cfg, to, text, accountId, replyToId }) =>
344	        await sendMessageIrc(to, text, {
345	          cfg: cfg as CoreConfig,
346	          accountId: accountId ?? undefined,
347	          replyTo: replyToId ?? undefined,
348	        }),
349	      sendMedia: async ({ cfg, to, text, mediaUrl, accountId, replyToId }) =>
350	        await sendMessageIrc(to, mediaUrl ? `${text}\n\nAttachment: ${mediaUrl}` : text, {
351	          cfg: cfg as CoreConfig,
352	          accountId: accountId ?? undefined,
353	          replyTo: replyToId ?? undefined,
354	        }),
355	    },
356	  },
357	});
