import { createChatChannelPlugin, getChatChannelMeta } from "openclaw/plugin-sdk/core";
import type { ChannelPlugin } from "openclaw/plugin-sdk/core";
import type { PulseBoardAccount } from "./types.js";

// Resolve meta from the plugin manifest registration at runtime.
// Cast required because "pulseboard" is registered as an extension channel,
// not a built-in ChatChannelId; the manifest supplies label/docsPath/blurb.
const meta = getChatChannelMeta("pulseboard" as Parameters<typeof getChatChannelMeta>[0]);

export const pulseBoardPlugin: ChannelPlugin<PulseBoardAccount> = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta,
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: {
      configPrefixes: ["channels.pulseboard"],
    },

    config: {
      listAccountIds: (cfg) => {
        // Stub: resolve account IDs from the channels.pulseboard config section
        const channelsCfg = cfg.channels as Record<string, unknown> | undefined;
        const pbCfg = channelsCfg?.pulseboard as
          | { accounts?: Record<string, unknown> }
          | undefined;
        return Object.keys(pbCfg?.accounts ?? {});
      },
      resolveAccount: (_cfg, accountId) => {
        // Stub: return a minimal placeholder; real impl would read from cfg
        return {
          boardUrl: "",
          apiToken: "",
          username: accountId ?? "default",
        } satisfies PulseBoardAccount;
      },
    },

    setup: {
      applyAccountConfig: ({ cfg }) => {
        // Stub: no-op; real impl would merge ChannelSetupInput values into cfg
        return cfg;
      },
    },

    gateway: {
      startAccount: async (ctx) => {
        // Stub: log connection start; real impl would open a WebSocket/polling loop
        ctx.log?.info?.(`PulseBoard: connecting account ${ctx.accountId}`);
      },
    },

    messaging: {
      normalizeTarget: (raw) => raw.trim() || undefined,
    },
  },

  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async (ctx) => {
      // Stub: real impl would POST to the PulseBoard REST API
      const messageId = `pb-${Date.now()}-${Math.random().toString(36).slice(2)}`;
      // Result carries: channel ("pulseboard"), to (ctx.to), and messageId
      return {
        channel: "pulseboard",
        messageId,
        meta: { to: ctx.to },
      };
    },
  },
});

